{
  "schemaVersion": "arkpilot-a2ui/v2-behavior",
  "uiTreePath": ".arkpilot/designs/ui-tree.json",
  "specPath": ".arkpilot/autopilot/spec.md",
  "implementationPhase": "headless-logic",
  "notes": "Behavior source of truth for 手作·印记 studio ops app. Design alignment artifacts not yet available; headless logic (models/services/controllers) is implemented first. Visual integration (final pages/components, shell tab migration from 4-tab template to 5-tab spec model, semantic .id bindings, final build) is deferred until design-alignment.md / page-*.html arrive.",
  "dataModel": {
    "entities": {
      "Member": {
        "fields": {
          "id": "string",
          "name": "string",
          "avatar": "string (rawfile/resource uri or empty)",
          "phone": "string",
          "note": "string",
          "crafts": "string[] (favorite craft names)",
          "skillLevel": "SkillLevel ('beginner'|'intermediate'|'advanced')",
          "points": "number (balance, derived/kept-in-sync with history sum)",
          "createdAt": "number (ms)",
          "lastVisitAt": "number (ms, 0 when never visited)",
          "lifetimeConsumption": "number",
          "portfolio": "PortfolioImage[]",
          "pointsHistory": "PointsRecord[]",
          "reachedOutAt": "number (ms, 0 when never reminded)"
        },
        "persistence": "local",
        "semanticBindings": ["member.avatar", "member.name", "member.crafts", "member.points", "member.portfolio", "member.pointsHistory"]
      },
      "PortfolioImage": {
        "fields": { "id": "string", "uri": "string", "caption": "string", "addedAt": "number" }
      },
      "PointsRecord": {
        "fields": { "id": "string", "delta": "number (+/-)", "reason": "string", "source": "PointsSource ('checkin'|'consumption'|'redemption'|'manual')", "relatedId": "string", "createdAt": "number" }
      },
      "Course": {
        "fields": {
          "id": "string",
          "title": "string",
          "description": "string",
          "cover": "string",
          "durationMin": "number",
          "capacity": "number",
          "category": "string",
          "materials": "CourseMaterial[]",
          "sessions": "Session[]",
          "createdAt": "number"
        },
        "semanticBindings": ["course.title", "course.capacity", "course.sessions", "course.materials"]
      },
      "CourseMaterial": {
        "fields": { "stockItemId": "string", "quantityPerAttendee": "number" }
      },
      "Session": {
        "fields": {
          "id": "string",
          "courseId": "string",
          "startAt": "number (ms)",
          "bookedMemberIds": "string[]",
          "attendedMemberIds": "string[]",
          "status": "SessionStatus ('open'|'full'|'completed'|'cancelled')",
          "materialDeducted": "boolean"
        }
      },
      "StockItem": {
        "fields": {
          "id": "string",
          "name": "string",
          "unit": "string",
          "quantity": "number",
          "lowStockThreshold": "number",
          "history": "StockAdjustment[]",
          "createdAt": "number"
        }
      },
      "StockAdjustment": {
        "fields": { "id": "string", "delta": "number", "reason": "string", "source": "StockSource ('manual'|'course')", "relatedId": "string", "createdAt": "number" }
      },
      "Settings": {
        "fields": {
          "studioName": "string",
          "checkinPoints": "number (points per check-in, default 10)",
          "consumptionRatio": "number (points awarded per currency unit spent, default 1)",
          "dormantDays": "number (default 30)"
        },
        "semanticBindings": ["studio.name", "rules.checkinPoints", "rules.consumptionRatio", "rules.dormantDays"]
      },
      "ActivityLog": {
        "fields": { "id": "string", "type": "ActivityType", "summary": "string", "createdAt": "number" }
      }
    },
    "settingsFormState": {
      "studio.name": "bound to Settings.studioName",
      "rules.checkinPoints": "bound to Settings.checkinPoints",
      "rules.consumptionRatio": "bound to Settings.consumptionRatio",
      "rules.dormantDays": "bound to Settings.dormantDays"
    },
    "computedState": {
      "/summary/count": "members.length (or dashboard summary count)",
      "/today/classes": "sessions where startAt is within today, joined with course title",
      "/alerts/dormant": "boolean: dormantMembers.length > 0",
      "/alerts/dormant/members": "members whose lastVisitAt > 0 and (now - lastVisitAt) > dormantDays*86400000, plus never-visited members older than dormantDays",
      "/alerts/lowstock": "boolean: lowStockItems.length > 0",
      "/alerts/lowstock/items": "stock items with quantity <= lowStockThreshold",
      "/recent/activity": "ActivityLog entries, newest first, capped",
      "/members": "member list filtered/sorted by query + sort mode",
      "/courses": "course list filtered by query + category",
      "/inventory": "stock items filtered by query + showLowStockOnly",
      "calendar.days": "month grid cells with session dot indicators",
      "calendar.selectedSessions": "sessions on the selected calendar day"
    },
    "persistenceFields": "Entire dataset { members[], courses[], inventory[], settings, activityLog[] } serialized to a single Preferences key as JSON. First-run state is empty (no preset seed data)."
  },
  "services": [
    {
      "name": "Store",
      "role": "Local-first persistence adapter over HarmonyOS Preferences (@kit.ArkData). Loads/saves the full dataset JSON. Async load on app init; synchronous in-memory access thereafter; debounced save after mutations.",
      "api": ["load(): Promise<AppData>", "save(data: AppData): Promise<void>"]
    },
    {
      "name": "AppStore",
      "role": "Central in-memory state singleton + all domain operations. Owns members/courses/inventory/settings/activity arrays and exposes event methods that mirror interactionFlows. Mutations mutate state then trigger Store.save.",
      "api": [
        "member CRUD: addMember, updateMember, deleteMember",
        "points: checkinMember, awardConsumptionPoints, redeemPoints, addManualPoints",
        "portfolio: addPortfolioImage",
        "dormant: getDormantMembers, markReachedOut",
        "course CRUD: addCourse",
        "booking: bookSeat (capacity check), markAttendance",
        "inventory: addStockItem, adjustStock, deductForSession",
        "settings: saveSettings",
        "computed selectors: todayClasses, dormantMembers, lowStockItems, recentActivity, monthGrid, sessionsOnDay"
      ]
    }
  ],
  "stateMachine": {
    "SessionStatus": {
      "states": ["open", "full", "completed", "cancelled"],
      "transitions": [
        { "from": "open", "to": "full", "event": "book-seat", "guard": "bookedMemberIds.length === capacity" },
        { "from": "open", "to": "open", "event": "book-seat", "guard": "bookedMemberIds.length < capacity" },
        { "from": ["open", "full"], "to": "completed", "event": "mark-attendance" },
        { "from": "*", "to": "cancelled", "event": "cancel-session" }
      ]
    },
    "MemberActivity": {
      "states": ["new", "active", "dormant"],
      "transitions": [
        { "from": "new", "to": "active", "event": "first-checkin" },
        { "from": "active", "to": "dormant", "event": "dormant-threshold-elapsed", "guard": "now - lastVisitAt > dormantDays*86400000" },
        { "from": "dormant", "to": "active", "event": "checkin" }
      ]
    },
    "StockLevel": {
      "states": ["ok", "low"],
      "transitions": [
        { "from": "ok", "to": "low", "event": "deduct", "guard": "quantity <= lowStockThreshold after deduction" },
        { "from": "low", "to": "ok", "event": "restock", "guard": "quantity > lowStockThreshold" }
      ]
    }
  },
  "interactionFlows": [
    {
      "flow": "open-checkin-sheet",
      "trigger": "dashboard-checkin-button tap",
