// Models.ets
//
// Pure data model for 手作·印记 (studio operations).
// Headless-logic phase: types only, no UI. Kept ArkTS-clean
// (string-literal unions, plain interfaces, no `any`, no untyped literals).
//
// These interfaces double as the serialization shape (DTO) so the same
// type is used for in-memory state and Preferences JSON persistence.

export type SkillLevel = 'beginner' | 'intermediate' | 'advanced';

export type PointsSource = 'checkin' | 'consumption' | 'redemption' | 'manual';

export type SessionStatus = 'open' | 'full' | 'completed' | 'cancelled';

export type StockSource = 'manual' | 'course';

export type ActivityType =
  | 'member-added'
  | 'member-checkin'
  | 'consumption'
  | 'course-added'
  | 'session-booked'
  | 'stock-deducted'
  | 'stock-adjusted'
  | 'reminder-sent'
  | 'settings-saved';

export interface PortfolioImage {
  id: string;
  uri: string;
  caption: string;
  addedAt: number;
}

export interface PointsRecord {
  id: string;
  delta: number; // +award / -redeem
  reason: string;
  source: PointsSource;
  relatedId: string; // empty when none
  createdAt: number;
}

export interface Member {
  id: string;
  name: string;
  avatar: string; // uri or empty
  phone: string;
  note: string;
  crafts: string[]; // favorite craft names
  skillLevel: SkillLevel;
