// Store.ets
//
// Local-first persistence for 手作·印记.
// Stores the entire dataset as one JSON document in HarmonyOS Preferences.
// First-run state is empty (no preset seed data).
//
// Headless-logic phase: no UI dependency. The AppStore holds the live
// in-memory dataset; Store only handles load/save.

import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';
import { AppData, Member, Course, StockItem, Settings, ActivityLog, emptyAppData } from '../common/models/Models';

const PREF_STORE: string = 'shouzuo_yinji_store';
const PREF_KEY_DATA: string = 'app_data_v1';

export class Store {
  private ctx: common.Context | null = null;

  attach(context: common.Context): void {
    this.ctx = context;
  }

  async load(): Promise<AppData> {
    if (this.ctx === null) {
      return emptyAppData();
    }
    try {
      const pref: preferences.Preferences = await preferences.getPreferences(this.ctx, PREF_STORE);
      const raw: string = (await pref.get(PREF_KEY_DATA, '')) as string;
      return this.deserialize(raw);
    } catch (err) {
      return emptyAppData();
    }
  }

  async save(data: AppData): Promise<void> {
    if (this.ctx === null) {
      return;
    }
    try {
      const pref: preferences.Preferences = await preferences.getPreferences(this.ctx, PREF_STORE);
      await pref.put(PREF_KEY_DATA, this.serialize(data));
      await pref.flush();
    } catch (err) {
      // Persistence failure is non-fatal for in-memory operation; AppStore keeps state.
    }
  }

  private serialize(data: AppData): string {
    return JSON.stringify(data);
  }

  private deserialize(raw: string): AppData {
    if (raw === null || raw === undefined || raw === '') {
      return emptyAppData();
    }
    const base: AppData = emptyAppData();
    try {
      const root: AppData = JSON.parse(raw) as AppData;
      base.members = this.normalizeMembers(root.members);
      base.courses = this.normalizeCourses(root.courses);
      base.inventory = this.normalizeInventory(root.inventory);
      base.activityLog = this.normalizeActivity(root.activityLog);
      base.settings = this.normalizeSettings(root.settings);
      base.idCounter = typeof root.idCounter === 'number' && root.idCounter > 0 ? root.idCounter : 1;
      return base;
    } catch (err) {
      return emptyAppData();
    }
  }

  private normalizeMembers(src: Member[] | undefined): Member[] {
    if (!Array.isArray(src)) {
      return [];
    }
    const out: Member[] = [];
    for (let i = 0; i < src.length; i++) {
      const m: Member = src[i];
      if (m === null || m === undefined || typeof m.id !== 'string') {
        continue;
      }
      out.push({
        id: m.id,
        name: typeof m.name === 'string' ? m.name : '',
        avatar: typeof m.avatar === 'string' ? m.avatar : '',
        phone: typeof m.phone === 'string' ? m.phone : '',
        note: typeof m.note === 'string' ? m.note : '',
        crafts: Array.isArray(m.crafts) ? m.crafts.filter((c: string) => typeof c === 'string') : [],
        skillLevel: m.skillLevel === 'beginner' || m.skillLevel === 'intermediate' || m.skillLevel === 'advanced'
          ? m.skillLevel : 'beginner',
        points: typeof m.points === 'number' ? m.points : 0,
        createdAt: typeof m.createdAt === 'number' ? m.createdAt : 0,
        lastVisitAt: typeof m.lastVisitAt === 'number' ? m.lastVisitAt : 0,
        lifetimeConsumption: typeof m.lifetimeConsumption === 'number' ? m.lifetimeConsumption : 0,
        reachedOutAt: typeof m.reachedOutAt === 'number' ? m.reachedOutAt : 0,
        portfolio: Array.isArray(m.portfolio) ? m.portfolio : [],
        pointsHistory: Array.isArray(m.pointsHistory) ? m.pointsHistory : [],
      });
    }
    return out;
  }

  private normalizeCourses(src: Course[] | undefined): Course[] {
    if (!Array.isArray(src)) {
      return [];
    }
    const out: Course[] = [];
    for (let i = 0; i < src.length; i++) {
      const c: Course = src[i];
      if (c === null || c === undefined || typeof c.id !== 'string') {
        continue;
      }
      out.push({
        id: c.id,
        title: typeof c.title === 'string' ? c.title : '',
        description: typeof c.description === 'string' ? c.description : '',
        cover: typeof c.cover === 'string' ? c.cover : '',
        durationMin: typeof c.durationMin === 'number' ? c.durationMin : 0,
        capacity: typeof c.capacity === 'number' ? c.capacity : 0,
        category: typeof c.category === 'string' ? c.category : '',
        materials: Array.isArray(c.materials) ? c.materials : [],
        sessions: Array.isArray(c.sessions) ? c.sessions : [],
        createdAt: typeof c.createdAt === 'number' ? c.createdAt : 0,
      });
    }
    return out;
  }

  private normalizeInventory(src: StockItem[] | undefined): StockItem[] {
    if (!Array.isArray(src)) {
      return [];
    }
    const out: StockItem[] = [];
    for (let i = 0; i < src.length; i++) {
      const it: StockItem = src[i];
      if (it === null || it === undefined || typeof it.id !== 'string') {
        continue;
      }
      out.push({
        id: it.id,
        name: typeof it.name === 'string' ? it.name : '',
        unit: typeof it.unit === 'string' ? it.unit : '',
        quantity: typeof it.quantity === 'number' ? it.quantity : 0,
        lowStockThreshold: typeof it.lowStockThreshold === 'number' ? it.lowStockThreshold : 0,
        history: Array.isArray(it.history) ? it.history : [],
        createdAt: typeof it.createdAt === 'number' ? it.createdAt : 0,
      });
    }
    return out;
  }

  private normalizeActivity(src: ActivityLog[] | undefined): ActivityLog[] {
    if (!Array.isArray(src)) {
      return [];
    }
    const out: ActivityLog[] = [];
    for (let i = 0; i < src.length; i++) {
      const a: ActivityLog = src[i];
      if (a === null || a === undefined || typeof a.id !== 'string') {
        continue;
      }
      out.push({
        id: a.id,
        type: a.type,
        summary: typeof a.summary === 'string' ? a.summary : '',
        createdAt: typeof a.createdAt === 'number' ? a.createdAt : 0,
      });
    }
    return out;
  }

  private normalizeSettings(src: Settings | undefined): Settings {
    const def: Settings = emptyAppData().settings;
    if (src === null || src === undefined) {
      return def;
    }
    return {
      studioName: typeof src.studioName === 'string' ? src.studioName : def.studioName,
      checkinPoints: typeof src.checkinPoints === 'number' && src.checkinPoints >= 0 ? src.checkinPoints : def.checkinPoints,
      consumptionRatio: typeof src.consumptionRatio === 'number' && src.consumptionRatio >= 0
        ? src.consumptionRatio : def.consumptionRatio,
      dormantDays: typeof src.dormantDays === 'number' && src.dormantDays >= 0 ? src.dormantDays : def.dormantDays,
    };
  }
}

