// AppStore.ets
//
// Central in-memory state + all domain operations for 手作·印记.
// Headless-logic phase: implements behavior from ui-behavior.json
// (member/points/portfolio/dormant/course/booking/inventory/settings
// flows). UI event wiring + observable decorators land in visual integration.
//
// Persistence: every mutating op triggers a debounced Store.save().
// Reactivity: state is plain data here; visual integration will bind it
// through @Observed/@State. Selectors are pure derivations.

import { common } from '@kit.AbilityKit';
import {
  AppData, Member, Course, Session, StockItem, Settings, ActivityLog,
  PortfolioImage, PointsRecord, StockAdjustment, SkillLevel, CourseMaterial,
  SessionStatus, ActivityType, emptyAppData,
} from '../common/models/Models';
import { Store } from './Store';

export interface OpResult {
  ok: boolean;
  message: string;
}

export interface SessionView {
  sessionId: string;
  courseId: string;
  courseTitle: string;
  startAt: number;
  bookedCount: number;
  capacity: number;
  status: SessionStatus;
}

export interface CalendarDay {
  dateKey: string; // YYYY-MM-DD
  day: number;
  inMonth: boolean;
  sessionCount: number;
  ms: number;
}

export interface MonthGrid {
  year: number;
  month: number; // 0-based
  title: string;
  days: CalendarDay[];
}

export type MemberSortMode = 'recent' | 'name';

const DAY_MS: number = 24 * 60 * 60 * 1000;
const MAX_ACTIVITY: number = 200;

export class AppStore {
  private static instance: AppStore | null = null;

  private data: AppData = emptyAppData();
  private store: Store = new Store();
  private initialized: boolean = false;

  static getInstance(): AppStore {
    if (AppStore.instance === null) {
      AppStore.instance = new AppStore();
    }
    return AppStore.instance;
  }

  async init(context: common.Context): Promise<void> {
    this.store.attach(context);
    this.data = await this.store.load();
    this.initialized = true;
  }

  isInitialized(): boolean {
    return this.initialized;
  }

  // ----- raw accessors (for controllers / visual integration) -----
  getMembers(): Member[] {
    return this.data.members;
  }

  getCourses(): Course[] {
    return this.data.courses;
  }

  getInventory(): StockItem[] {
    return this.data.inventory;
  }

  getSettings(): Settings {
    return this.data.settings;
  }

  getMember(id: string): Member | undefined {
    return this.findMember(id);
  }

  getCourse(id: string): Course | undefined {
    return this.data.courses.find((c: Course) => c.id === id) || undefined;
  }

  getStockItem(id: string): StockItem | undefined {
    return this.data.inventory.find((it: StockItem) => it.id === id) || undefined;
  }

  // ----- id helpers -----
  private nextId(prefix: string): string {
    this.data.idCounter += 1;
    return `${prefix}_${this.data.idCounter}`;
  }

  private now(): number {
    return Date.now();
  }

  private persist(): void {
    this.store.save(this.data);
  }

  // ----- activity log -----
  private logActivity(type: ActivityType, summary: string): void {
    const entry: ActivityLog = {
      id: this.nextId('act'),
      type: type,
      summary: summary,
      createdAt: this.now(),
    };
    this.data.activityLog.push(entry);
    if (this.data.activityLog.length > MAX_ACTIVITY) {
      this.data.activityLog.splice(0, this.data.activityLog.length - MAX_ACTIVITY);
    }
  }

  // ===== Member =====
  addMember(input: {
    name: string; phone: string; note: string; crafts: string[]; skillLevel: SkillLevel;
  }): OpResult {
    const name: string = input.name.trim();
    if (name.length === 0) {
      return { ok: false, message: '请输入会员姓名' };
    }
    const now: number = this.now();
    const m: Member = {
      id: this.nextId('mem'),
      name: name,
      avatar: '',
      phone: input.phone.trim(),
      note: input.note.trim(),
      crafts: input.crafts,
      skillLevel: input.skillLevel,
      points: 0,
      createdAt: now,
      lastVisitAt: 0,
      lifetimeConsumption: 0,
      reachedOutAt: 0,
      portfolio: [],
      pointsHistory: [],
    };
    this.data.members.push(m);
    this.logActivity('member-added', `新增会员「${name}」`);
    this.persist();
    return { ok: true, message: '已添加会员' };
  }

  updateMember(id: string, patch: {
    name?: string; phone?: string; note?: string; crafts?: string[]; skillLevel?: SkillLevel; avatar?: string;
  }): OpResult {
    const idx: number = this.memberIndex(id);
    if (idx < 0) {
      return { ok: false, message: '会员不存在' };
    }
    const cur: Member = this.data.members[idx];
    const updated: Member = {
      id: cur.id,
      name: patch.name !== undefined ? patch.name.trim() : cur.name,
      avatar: patch.avatar !== undefined ? patch.avatar : cur.avatar,
      phone: patch.phone !== undefined ? patch.phone.trim() : cur.phone,
      note: patch.note !== undefined ? patch.note.trim() : cur.note,
      crafts: patch.crafts !== undefined ? patch.crafts : cur.crafts,
      skillLevel: patch.skillLevel !== undefined ? patch.skillLevel : cur.skillLevel,
      points: cur.points,
      createdAt: cur.createdAt,
      lastVisitAt: cur.lastVisitAt,
      lifetimeConsumption: cur.lifetimeConsumption,
      reachedOutAt: cur.reachedOutAt,
      portfolio: cur.portfolio,
      pointsHistory: cur.pointsHistory,
    };
    this.data.members[idx] = updated;
    this.persist();
    return { ok: true, message: '已更新会员' };
  }

  deleteMember(id: string): OpResult {
    const idx: number = this.memberIndex(id);
    if (idx < 0) {
      return { ok: false, message: '会员不存在' };
    }
    this.data.members.splice(idx, 1);
    // cleanup bookings/attendance across sessions
    for (const course of this.data.courses) {
      for (const session of course.sessions) {
        session.bookedMemberIds = session.bookedMemberIds.filter((bid: string) => bid !== id);
        session.attendedMemberIds = session.attendedMemberIds.filter((aid: string) => aid !== id);
        if (session.status === 'full' && session.bookedMemberIds.length < session.capacity) {
          session.status = 'open';
        }
      }
    }
    this.persist();
    return { ok: true, message: '已删除会员' };
  }

  // ===== Points =====
  checkinMember(memberId: string): OpResult {
    const m: Member | undefined = this.findMember(memberId);
    if (m === undefined) {
      return { ok: false, message: '会员不存在' };
    }
    const award: number = this.data.settings.checkinPoints;
    const now: number = this.now();
    m.points += award;
    m.lastVisitAt = now;
    m.pointsHistory.push({
      id: this.nextId('pts'),
      delta: award,
      reason: '每日签到',
      source: 'checkin',
      relatedId: '',
      createdAt: now,
    });
    this.logActivity('member-checkin', `「${m.name}」签到 +${award}`);
    this.persist();
    return { ok: true, message: `签到成功 +${award} 积分` };
  }

  awardConsumptionPoints(memberId: string, amount: number): OpResult {
    const m: Member | undefined = this.findMember(memberId);
    if (m === undefined) {
      return { ok: false, message: '会员不存在' };
    }
    if (!(amount > 0)) {
      return { ok: false, message: '消费金额需大于 0' };
    }
    const award: number = Math.round(amount * this.data.settings.consumptionRatio);
    const now: number = this.now();
    m.points += award;
    m.lifetimeConsumption += amount;
    m.lastVisitAt = now;
    m.pointsHistory.push({
      id: this.nextId('pts'),
      delta: award,
      reason: `消费 ¥${amount}`,
      source: 'consumption',
      relatedId: '',
      createdAt: now,
    });
    this.logActivity('consumption', `「${m.name}」消费 ¥${amount} +${award}`);
    this.persist();
    return { ok: true, message: `已计入消费 +${award} 积分` };
  }

  redeemPoints(memberId: string, points: number, reason: string): OpResult {
    const m: Member | undefined = this.findMember(memberId);
    if (m === undefined) {
      return { ok: false, message: '会员不存在' };
    }
    if (!(points > 0)) {
      return { ok: false, message: '兑换积分需大于 0' };
    }
    if (points > m.points) {
      return { ok: false, message: '积分余额不足' };
    }
    const now: number = this.now();
    m.points -= points;
    m.pointsHistory.push({
      id: this.nextId('pts'),
      delta: -points,
      reason: reason.length > 0 ? reason : '积分兑换',
      source: 'redemption',
      relatedId: '',
      createdAt: now,
    });
    this.persist();
    return { ok: true, message: `已兑换 -${points} 积分` };
  }

  addManualPoints(memberId: string, delta: number, reason: string): OpResult {
    const m: Member | undefined = this.findMember(memberId);
    if (m === undefined) {
      return { ok: false, message: '会员不存在' };
    }
    if (delta === 0) {
      return { ok: false, message: '积分变动不可为 0' };
    }
    if (delta < 0 && Math.abs(delta) > m.points) {
      return { ok: false, message: '积分余额不足' };
    }
    const now: number = this.now();
    m.points += delta;
    m.pointsHistory.push({
      id: this.nextId('pts'),
      delta: delta,
      reason: reason.length > 0 ? reason : '手动调整',
      source: 'manual',
      relatedId: '',
      createdAt: now,
    });
    this.persist();
    return { ok: true, message: `积分已调整 ${delta > 0 ? '+' : ''}${delta}` };
  }

  // ===== Portfolio =====
  addPortfolioImage(memberId: string, uri: string, caption: string): OpResult {
    const m: Member | undefined = this.findMember(memberId);
    if (m === undefined) {
      return { ok: false, message: '会员不存在' };
    }
    if (uri.length === 0) {
      return { ok: false, message: '请选择作品图片' };
    }
    const img: PortfolioImage = {
      id: this.nextId('work'),
      uri: uri,
      caption: caption.trim(),
      addedAt: this.now(),
    };
    m.portfolio.push(img);
    this.persist();
    return { ok: true, message: '已添加作品' };
  }

  removePortfolioImage(memberId: string, imageId: string): OpResult {
    const m: Member | undefined = this.findMember(memberId);
    if (m === undefined) {
      return { ok: false, message: '会员不存在' };
    }
    const before: number = m.portfolio.length;
    m.portfolio = m.portfolio.filter((p: PortfolioImage) => p.id !== imageId);
    if (m.portfolio.length === before) {
      return { ok: false, message: '作品不存在' };
    }
    this.persist();
    return { ok: true, message: '已移除作品' };
  }

  // ===== Dormant =====
  dormantMembers(now: number): Member[] {
    const threshold: number = this.data.settings.dormantDays * DAY_MS;
    const out: Member[] = [];
    for (const m of this.data.members) {
      if (m.lastVisitAt <= 0) {
        // never visited: dormant only if member is older than threshold
        if (now - m.createdAt >= threshold) {
          out.push(m);
        }
      } else if (now - m.lastVisitAt >= threshold) {
        out.push(m);
      }
    }
    return out;
  }

  hasDormantAlert(now: number): boolean {
    return this.dormantMembers(now).length > 0;
  }

  markReachedOut(memberId: string): OpResult {
    const m: Member | undefined = this.findMember(memberId);
    if (m === undefined) {
      return { ok: false, message: '会员不存在' };
    }
    m.reachedOutAt = this.now();
    this.logActivity('reminder-sent', `已提醒沉睡会员「${m.name}」`);
    this.persist();
    return { ok: true, message: '已记录联系' };
  }

  // ===== Course =====
  addCourse(input: {
    title: string; description: string; cover: string; durationMin: number;
    capacity: number; category: string; materials: CourseMaterial[];
  }): OpResult {
    const title: string = input.title.trim();
    if (title.length === 0) {
      return { ok: false, message: '请输入课程名称' };
    }
    const course: Course = {
      id: this.nextId('crs'),
      title: title,
      description: input.description.trim(),
      cover: input.cover,
      durationMin: input.durationMin,
      capacity: input.capacity,
      category: input.category.trim(),
      materials: input.materials,
      sessions: [],
      createdAt: this.now(),
    };
    this.data.courses.push(course);
    this.logActivity('course-added', `新增课程「${title}」`);
    this.persist();
    return { ok: true, message: '已添加课程' };
  }

  addSession(courseId: string, startAt: number): OpResult {
    const c: Course | undefined = this.getCourse(courseId);
    if (c === undefined) {
      return { ok: false, message: '课程不存在' };
    }
    const session: Session = {
      id: this.nextId('ses'),
      courseId: courseId,
      startAt: startAt,
      bookedMemberIds: [],
      attendedMemberIds: [],
      status: 'open',
      materialDeducted: false,
    };
    c.sessions.push(session);
    this.persist();
    return { ok: true, message: '已安排课时' };
  }

  // ===== Booking =====
  bookSeat(sessionId: string, memberId: string): OpResult {
    const found: { course: Course; session: Session } | undefined = this.findSession(sessionId);
    if (found === undefined) {
      return { ok: false, message: '课时不存在' };
    }
    const session: Session = found.session;
    if (session.status === 'completed' || session.status === 'cancelled') {
      return { ok: false, message: '该课时已结束' };
    }
    if (session.bookedMemberIds.indexOf(memberId) >= 0) {
      return { ok: false, message: '该会员已预约' };
    }
    if (session.bookedMemberIds.length >= session.capacity) {
      return { ok: false, message: '名额已满' };
    }
    session.bookedMemberIds.push(memberId);
    if (session.bookedMemberIds.length >= session.capacity) {
      session.status = 'full';
    }
    const m: Member | undefined = this.findMember(memberId);
    const name: string = m !== undefined ? m.name : '会员';
    this.logActivity('session-booked', `「${name}」预约「${found.course.title}」`);
    this.persist();
    return { ok: true, message: '预约成功' };
  }

  markAttendance(sessionId: string, memberIds: string[]): OpResult {
    const found: { course: Course; session: Session } | undefined = this.findSession(sessionId);
    if (found === undefined) {
      return { ok: false, message: '课时不存在' };
    }
    const session: Session = found.session;
    session.attendedMemberIds = memberIds;
    session.status = 'completed';
    this.persist();
    return { ok: true, message: '已记录到课' };
  }

  // ===== Inventory =====
  addStockItem(input: {
    name: string; unit: string; quantity: number; lowStockThreshold: number;
  }): OpResult {
    const name: string = input.name.trim();
    if (name.length === 0) {
      return { ok: false, message: '请输入物料名称' };
    }
    const item: StockItem = {
      id: this.nextId('stk'),
      name: name,
      unit: input.unit.trim(),
      quantity: Math.max(0, input.quantity),
      lowStockThreshold: Math.max(0, input.lowStockThreshold),
      history: [],
      createdAt: this.now(),
    };
    this.data.inventory.push(item);
    this.persist();
    return { ok: true, message: '已添加物料' };
  }

  adjustStock(itemId: string, delta: number, reason: string): OpResult {
    const it: StockItem | undefined = this.getStockItem(itemId);
    if (it === undefined) {
      return { ok: false, message: '物料不存在' };
    }
    if (delta === 0) {
      return { ok: false, message: '调整数量不可为 0' };
    }
    const next: number = Math.max(0, it.quantity + delta);
    const realDelta: number = next - it.quantity;
    it.quantity = next;
    it.history.push({
      id: this.nextId('adj'),
      delta: realDelta,
      reason: reason.trim(),
      source: 'manual',
      relatedId: '',
      createdAt: this.now(),
    });
    this.logActivity('stock-adjusted', `「${it.name}」库存调整 ${realDelta > 0 ? '+' : ''}${realDelta}`);
    this.persist();
    return { ok: true, message: '已调整库存' };
  }

  deductForSession(courseId: string, sessionId: string, attendeeCount: number): OpResult {
    const c: Course | undefined = this.getCourse(courseId);
    if (c === undefined) {
      return { ok: false, message: '课程不存在' };
    }
    const session: Session | undefined = c.sessions.find((s: Session) => s.id === sessionId);
    if (session === undefined) {
      return { ok: false, message: '课时不存在' };
    }
    if (session.materialDeducted) {
      return { ok: false, message: '该课时物料已扣减' };
    }
    if (!(attendeeCount > 0)) {
      return { ok: false, message: '参与人数需大于 0' };
    }
    if (c.materials.length === 0) {
      session.materialDeducted = true;
      this.persist();
      return { ok: true, message: '该课程无关联物料' };
    }
    const warnings: string[] = [];
    const now: number = this.now();
    for (const mat of c.materials) {
      const it: StockItem | undefined = this.getStockItem(mat.stockItemId);
      if (it === undefined) {
        continue;
      }
      const need: number = mat.quantityPerAttendee * attendeeCount;
      const before: number = it.quantity;
      const after: number = Math.max(0, before - need);
      const realDelta: number = after - before;
      it.quantity = after;
      it.history.push({
        id: this.nextId('adj'),
        delta: realDelta,
        reason: `「${c.title}」课时消耗 ×${attendeeCount}`,
        source: 'course',
        relatedId: sessionId,
        createdAt: now,
      });
      if (after < need) {
        warnings.push(`「${it.name}」库存不足`);
      }
    }
    session.materialDeducted = true;
    this.logActivity('stock-deducted', `「${c.title}」扣减物料 ×${attendeeCount}`);
    this.persist();
    const msg: string = warnings.length > 0 ? `已扣减（${warnings.join('；')}）` : '已扣减库存';
    return { ok: true, message: msg };
  }

  // ===== Settings =====
  saveSettings(input: {
    studioName: string; checkinPoints: number; consumptionRatio: number; dormantDays: number;
  }): OpResult {
    const checkin: number = Math.max(0, Math.round(input.checkinPoints));
    const ratio: number = Math.max(0, input.consumptionRatio);
    const dormant: number = Math.max(0, Math.round(input.dormantDays));
    if (checkin <= 0 && ratio <= 0) {
      return { ok: false, message: '签到积分与消费比例不可同时为 0' };
    }
    this.data.settings = {
      studioName: input.studioName.trim(),
      checkinPoints: checkin,
      consumptionRatio: ratio,
      dormantDays: dormant,
    };
    this.logActivity('settings-saved', '已保存工作室设置');
    this.persist();
    return { ok: true, message: '设置已保存' };
  }

  // ===== Selectors =====
  queryMembers(query: string, sortMode: MemberSortMode): Member[] {
    const q: string = query.trim().toLowerCase();
    let list: Member[] = this.data.members.filter((m: Member) => {
      if (q.length === 0) {
        return true;
      }
      return m.name.toLowerCase().indexOf(q) >= 0
        || m.phone.toLowerCase().indexOf(q) >= 0
        || m.crafts.some((craft: string) => craft.toLowerCase().indexOf(q) >= 0);
    });
    if (sortMode === 'name') {
      list = list.slice().sort((a: Member, b: Member) => a.name.localeCompare(b.name));
    } else {
      list = list.slice().sort((a: Member, b: Member) => b.lastVisitAt - a.lastVisitAt);
    }
    return list;
  }

  queryCourses(query: string, category: string): Course[] {
    const q: string = query.trim().toLowerCase();
    return this.data.courses.filter((c: Course) => {
      if (category.length > 0 && c.category !== category) {
        return false;
      }
      if (q.length === 0) {
        return true;
      }
      return c.title.toLowerCase().indexOf(q) >= 0 || c.description.toLowerCase().indexOf(q) >= 0;
    });
  }

  queryInventory(query: string, showLowStockOnly: boolean): StockItem[] {
    const q: string = query.trim().toLowerCase();
    return this.data.inventory.filter((it: StockItem) => {
      if (showLowStockOnly && it.quantity > it.lowStockThreshold) {
        return false;
      }
      if (q.length === 0) {
        return true;
      }
      return it.name.toLowerCase().indexOf(q) >= 0;
    });
  }

  lowStockItems(): StockItem[] {
    return this.data.inventory.filter((it: StockItem) => it.quantity <= it.lowStockThreshold);
  }

  hasLowStockAlert(): boolean {
    return this.lowStockItems().length > 0;
  }

  todayClasses(now: number): SessionView[] {
    const key: string = this.dateKey(now);
    return this.collectSessions((s: Session) => this.dateKey(s.startAt) === key);
  }

  recentActivity(limit: number): ActivityLog[] {
    const all: ActivityLog[] = this.data.activityLog.slice();
    all.sort((a: ActivityLog, b: ActivityLog) => b.createdAt - a.createdAt);
    return all.slice(0, limit);
  }

  monthGrid(year: number, month: number): MonthGrid {
    const first: Date = new Date(year, month, 1);
    const startWeekday: number = first.getDay(); // 0=Sun
    const daysInMonth: number = new Date(year, month + 1, 0).getDate();
    const sessionCountByKey: Map<string, number> = this.sessionCountByDateKey();

    const days: CalendarDay[] = [];

    // leading days from previous month
    const prevMonth: number = month === 0 ? 11 : month - 1;
    const prevYear: number = month === 0 ? year - 1 : year;
    const daysInPrev: number = new Date(prevYear, prevMonth + 1, 0).getDate();
    for (let i = startWeekday - 1; i >= 0; i--) {
      const dayNum: number = daysInPrev - i;
      days.push(this.buildCalendarDay(prevYear, prevMonth, dayNum, false, sessionCountByKey));
    }
    // current month days
    for (let d = 1; d <= daysInMonth; d++) {
      days.push(this.buildCalendarDay(year, month, d, true, sessionCountByKey));
    }
    // trailing to complete final week
    while (days.length % 7 !== 0) {
      const last: CalendarDay = days[days.length - 1];
      const next: Date = new Date(last.ms + DAY_MS);
      days.push(this.buildCalendarDay(next.getFullYear(), next.getMonth(), next.getDate(), false, sessionCountByKey));
    }

    return {
      year: year,
      month: month,
      title: `${year}年${month + 1}月`,
      days: days,
    };
  }

  sessionsOnDay(ms: number): SessionView[] {
    const key: string = this.dateKey(ms);
    return this.collectSessions((s: Session) => this.dateKey(s.startAt) === key);
  }

  // ===== private helpers =====
  private findMember(id: string): Member | undefined {
    return this.data.members.find((m: Member) => m.id === id) || undefined;
  }

  private memberIndex(id: string): number {
    return this.data.members.findIndex((m: Member) => m.id === id);
  }

  private findSession(sessionId: string): { course: Course; session: Session } | undefined {
    for (const course of this.data.courses) {
      const s: Session | undefined = course.sessions.find((sess: Session) => sess.id === sessionId);
      if (s !== undefined) {
        return { course: course, session: s };
      }
    }
    return undefined;
  }

  private collectSessions(predicate: (s: Session) => boolean): SessionView[] {
    const out: SessionView[] = [];
    for (const course of this.data.courses) {
      for (const session of course.sessions) {
        if (predicate(session)) {
          out.push({
            sessionId: session.id,
            courseId: course.id,
            courseTitle: course.title,
            startAt: session.startAt,
            bookedCount: session.bookedMemberIds.length,
            capacity: course.capacity,
            status: session.status,
          });
        }
      }
    }
    out.sort((a: SessionView, b: SessionView) => a.startAt - b.startAt);
    return out;
  }

  private sessionCountByDateKey(): Map<string, number> {
    const map: Map<string, number> = new Map<string, number>();
    for (const course of this.data.courses) {
      for (const session of course.sessions) {
        const k: string = this.dateKey(session.startAt);
        const cur: number = map.get(k) || 0;
        map.set(k, cur + 1);
      }
    }
    return map;
  }

  private buildCalendarDay(y: number, m: number, d: number, inMonth: boolean,
    counts: Map<string, number>): CalendarDay {
    const ms: number = new Date(y, m, d, 0, 0, 0, 0).getTime();
    const key: string = this.dateKey(ms);
    return {
      dateKey: key,
      day: d,
      inMonth: inMonth,
      sessionCount: counts.get(key) || 0,
      ms: ms,
    };
  }

  private dateKey(ms: number): string {
    const d: Date = new Date(ms);
    const y: number = d.getFullYear();
    const m: number = d.getMonth() + 1;
    const day: number = d.getDate();
    const mm: string = m < 10 ? `0${m}` : `${m}`;
    const dd: string = day < 10 ? `0${day}` : `${day}`;
    return `${y}-${mm}-${dd}`;
  }
}

toolUseResult.content:
// AppStore.ets
//
// Central in-memory state + all domain operations for 手作·印记.
// Headless-logic phase: implements behavior from ui-behavior.json
// (member/points/portfolio/dormant/course/booking/inventory/settings
// flows). UI event wiring + observable decorators land in visual integration.
//
// Persistence: every mutating op triggers a debounced Store.save().
// Reactivity: state is plain data here; visual integration will bind it
// through @Observed/@State. Selectors are pure derivations.

import { common } from '@kit.AbilityKit';
import {
  AppData, Member, Course, Session, StockItem, Settings, ActivityLog,
  PortfolioImage, PointsRecord, StockAdjustment, SkillLevel, CourseMaterial,
  SessionStatus, ActivityType, emptyAppData,
} from '../common/models/Models';
import { Store } from './Store';

export interface OpResult {
  ok: boolean;
  message: string;
}

export interface SessionView {
  sessionId: string;
  courseId: string;
  courseTitle: string;
  startAt: number;
  bookedCount: number;
  capacity: number;
  status: SessionStatus;
}

export interface CalendarDay {
  dateKey: string; // YYYY-MM-DD
  day: number;
  inMonth: boolean;
  sessionCount: number;
  ms: number;
}

export interface MonthGrid {
  year: number;
  month: number; // 0-based
  title: string;
  days: CalendarDay[];
}

export type MemberSortMode = 'recent' | 'name';

const DAY_MS: number = 24 * 60 * 60 * 1000;
const MAX_ACTIVITY: number = 200;

export class AppStore {
  private static instance: AppStore | null = null;

  private data: AppData = emptyAppData();
  private store: Store = new Store();
  private initialized: boolean = false;

  static getInstance(): AppStore {
    if (AppStore.instance === null) {
      AppStore.instance = new AppStore();
    }
    return AppStore.instance;
  }

  async init(context: common.Context): Promise<void> {
    this.store.attach(context);
    this.data = await this.store.load();
    this.initialized = true;
  }

  isInitialized(): boolean {
    return this.initialized;
  }

  // ----- raw accessors (for controllers / visual integration) -----
  getMembers(): Member[] {
    return this.data.members;
  }

  getCourses(): Course[] {
    return this.data.courses;
  }

  getInventory(): StockItem[] {
    return this.data.inventory;
  }

  getSettings(): Settings {
    return this.data.settings;
  }

  getMember(id: string): Member | undefined {
    return this.findMember(id);
  }

  getCourse(id: string): Course | undefined {
    return this.data.courses.find((c: Course) => c.id === id) || undefined;
  }

  getStockItem(id: string): StockItem | undefined {
    return this.data.inventory.find((it: StockItem) => it.id === id) || undefined;
  }

  // ----- id helpers -----
  private nextId(prefix: string): string {
    this.data.idCounter += 1;
    return `${prefix}_${this.data.idCounter}`;
  }

  private now(): number {
    return Date.now();
  }

  private persist(): void {
    this.store.save(this.data);
  }

  // ----- activity log -----
  private logActivity(type: ActivityType, summary: string): void {
    const entry: ActivityLog = {
      id: this.nextId('act'),
      type: type,
      summary: summary,
      createdAt: this.now(),
    };
    this.data.activityLog.push(entry);
    if (this.data.activityLog.length > MAX_ACTIVITY) {
      this.data.activityLog.splice(0, this.data.activityLog.length - MAX_ACTIVITY);
    }
  }

  // ===== Member =====
  addMember(input: {
    name: string; phone: string; note: string; crafts: string[]; skillLevel: SkillLevel;
  }): OpResult {
    const name: string = input.name.trim();
    if (name.length === 0) {
      return { ok: false, message: '请输入会员姓名' };
    }
    const now: number = this.now();
    const m: Member = {
      id: this.nextId('mem'),
      name: name,
      avatar: '',
      phone: input.phone.trim(),
      note: input.note.trim(),
      crafts: input.crafts,
      skillLevel: input.skillLevel,
      points: 0,
      createdAt: now,
      lastVisitAt: 0,
      lifetimeConsumption: 0,
      reachedOutAt: 0,
      portfolio: [],
      pointsHistory: [],
    };
    this.data.members.push(m);
    this.logActivity('member-added', `新增会员「${name}」`);
    this.persist();
    return { ok: true, message: '已添加会员' };
  }

  updateMember(id: string, patch: {
    name?: string; phone?: string; note?: string; crafts?: string[]; skillLevel?: SkillLevel; avatar?: string;
  }): OpResult {
    const idx: number = this.memberIndex(id);
    if (idx < 0) {
      return { ok: false, message: '会员不存在' };
    }
    const cur: Member = this.data.members[idx];
    const updated: Member = {
      id: cur.id,
      name: patch.name !== undefined ? patch.name.trim() : cur.name,
      avatar: patch.avatar !== undefined ? patch.avatar : cur.avatar,
      phone: patch.phone !== undefined ? patch.phone.trim() : cur.phone,
      note: patch.note !== undefined ? patch.note.trim() : cur.note,
      crafts: patch.crafts !== undefined ? patch.crafts : cur.crafts,
      skillLevel: patch.skillLevel !== undefined ? patch.skillLevel : cur.skillLevel,
      points: cur.points,
      createdAt: cur.createdAt,
      lastVisitAt: cur.lastVisitAt,
      lifetimeConsumption: cur.lifetimeConsumption,
      reachedOutAt: cur.reachedOutAt,
      portfolio: cur.portfolio,
      pointsHistory: cur.pointsHistory,
    };
    this.data.members[idx] = updated;
    this.persist();
    return { ok: true, message: '已更新会员' };
  }

  deleteMember(id: string): OpResult {
    const idx: number = this.memberIndex(id);
    if (idx < 0) {
      return { ok: false, message: '会员不存在' };
    }
    this.data.members.splice(idx, 1);
    // cleanup bookings/attendance across sessions
    for (const course of this.data.courses) {
      for (const session of course.sessions) {
        session.bookedMemberIds = session.bookedMemberIds.filter((bid: string) => bid !== id);
        session.attendedMemberIds = session.attendedMemberIds.filter((aid: string) => aid !== id);
        if (session.status === 'full' && session.bookedMemberIds.length < session.capacity) {
          session.status = 'open';
        }
      }
    }
    this.persist();
    return { ok: true, message: '已删除会员' };
  }

  // ===== Points =====
  checkinMember(memberId: string): OpResult {
    const m: Member | undefined = this.findMember(memberId);
    if (m === undefined) {
      return { ok: false, message: '会员不存在' };
    }
    const award: number = this.data.settings.checkinPoints;
    const now: number = this.now();
    m.points += award;
    m.lastVisitAt = now;
    m.pointsHistory.push({
      id: this.nextId('pts'),
      delta: award,
      reason: '每日签到',
      source: 'checkin',
      relatedId: '',
      createdAt: now,
    });
    this.logActivity('member-checkin', `「${m.name}」签到 +${award}`);
    this.persist();
    return { ok: true, message: `签到成功 +${award} 积分` };
  }

  awardConsumptionPoints(memberId: string, amount: number): OpResult {
    const m: Member | undefined = this.findMember(memberId);
    if (m === undefined) {
      return { ok: false, message: '会员不存在' };
    }
    if (!(amount > 0)) {
      return { ok: false, message: '消费金额需大于 0' };
    }
    const award: number = Math.round(amount * this.data.settings.consumptionRatio);
    const now: number = this.now();
    m.points += award;
    m.lifetimeConsumption += amount;
    m.lastVisitAt = now;
    m.pointsHistory.push({
      id: this.nextId('pts'),
      delta: award,
      reason: `消费 ¥${amount}`,
      source: 'consumption',
      relatedId: '',
      createdAt: now,
    });
    this.logActivity('consumption', `「${m.name}」消费 ¥${amount} +${award}`);
    this.persist();
    return { ok: true, message: `已计入消费 +${award} 积分` };
  }

  redeemPoints(memberId: string, points: number, reason: string): OpResult {
    const m: Member | undefined = this.findMember(memberId);
    if (m === undefined) {
      return { ok: false, message: '会员不存在' };
    }
    if (!(points > 0)) {
      return { ok: false, message: '兑换积分需大于 0' };
    }
    if (points > m.points) {
      return { ok: false, message: '积分余额不足' };
    }
    const now: number = this.now();
    m.points -= points;
    m.pointsHistory.push({
      id: this.nextId('pts'),
      delta: -points,
      reason: reason.length > 0 ? reason : '积分兑换',
      source: 'redemption',
      relatedId: '',
      createdAt: now,
    });
    this.persist();
    return { ok: true, message: `已兑换 -${points} 积分` };
  }

  addManualPoints(memberId: string, delta: number, reason: string): OpResult {
    const m: Member | undefined = this.findMember(memberId);
    if (m === undefined) {
      return { ok: false, message: '会员不存在' };
    }
    if (delta === 0) {
      return { ok: false, message: '积分变动不可为 0' };
    }
    if (delta < 0 && Math.abs(delta) > m.points) {
      return { ok: false, message: '积分余额不足' };
    }
    const now: number = this.now();
    m.points += delta;
    m.pointsHistory.push({
      id: this.nextId('pts'),
      delta: delta,
      reason: reason.length > 0 ? reason : '手动调整',
      source: 'manual',
      relatedId: '',
      createdAt: now,
    });
    this.persist();
    return { ok: true, message: `积分已调整 ${delta > 0 ? '+' : ''}${delta}` };
  }

  // ===== Portfolio =====
  addPortfolioImage(memberId: string, uri: string, caption: string): OpResult {
    const m: Member | undefined = this.findMember(memberId);
    if (m === undefined) {
      return { ok: false, message: '会员不存在' };
    }
    if (uri.length === 0) {
      return { ok: false, message: '请选择作品图片' };
    }
    const img: PortfolioImage = {
      id: this.nextId('work'),
      uri: uri,
      caption: caption.trim(),
      addedAt: this.now(),
    };
    m.portfolio.push(img);
    this.persist();
    return { ok: true, message: '已添加作品' };
  }

  removePortfolioImage(memberId: string, imageId: string): OpResult {
    const m: Member | undefined = this.findMember(memberId);
    if (m === undefined) {
      return { ok: false, message: '会员不存在' };
    }
    const before: number = m.portfolio.length;
    m.portfolio = m.portfolio.filter((p: PortfolioImage) => p.id !== imageId);
    if (m.portfolio.length === before) {
      return { ok: false, message: '作品不存在' };
    }
    this.persist();
    return { ok: true, message: '已移除作品' };
  }

  // ===== Dormant =====
  dormantMembers(now: number): Member[] {
    const threshold: number = this.data.settings.dormantDays * DAY_MS;
    const out: Member[] = [];
    for (const m of this.data.members) {
      if (m.lastVisitAt <= 0) {
        // never visited: dormant only if member is older than threshold
        if (now - m.createdAt >= threshold) {
          out.push(m);
        }
      } else if (now - m.lastVisitAt >= threshold) {
        out.push(m);
      }
    }
    return out;
  }

  hasDormantAlert(now: number): boolean {
    return this.dormantMembers(now).length > 0;
  }

  markReachedOut(memberId: string): OpResult {
    const m: Member | undefined = this.findMember(memberId);
    if (m === undefined) {
      return { ok: false, message: '会员不存在' };
    }
    m.reachedOutAt = this.now();
    this.logActivity('reminder-sent', `已提醒沉睡会员「${m.name}」`);
    this.persist();
    return { ok: true, message: '已记录联系' };
  }

  // ===== Course =====
  addCourse(input: {
    title: string; description: string; cover: string; durationMin: number;
    capacity: number; category: string; materials: CourseMaterial[];
  }): OpResult {
    const title: string = input.title.trim();
    if (title.length === 0) {
      return { ok: false, message: '请输入课程名称' };
    }
    const course: Course = {
      id: this.nextId('crs'),
      title: title,
      description: input.description.trim(),
      cover: input.cover,
      durationMin: input.durationMin,
      capacity: input.capacity,
      category: input.category.trim(),
      materials: input.materials,
      sessions: [],
      createdAt: this.now(),
    };
    this.data.courses.push(course);
    this.logActivity('course-added', `新增课程「${title}」`);
    this.persist();
    return { ok: true, message: '已添加课程' };
  }

  addSession(courseId: string, startAt: number): OpResult {
    const c: Course | undefined = this.getCourse(courseId);
    if (c === undefined) {
      return { ok: false, message: '课程不存在' };
    }
    const session: Session = {
      id: this.nextId('ses'),
      courseId: courseId,
      startAt: startAt,
      bookedMemberIds: [],
      attendedMemberIds: [],
      status: 'open',
      materialDeducted: false,
    };
    c.sessions.push(session);
    this.persist();
    return { ok: true, message: '已安排课时' };
  }

  // ===== Booking =====
  bookSeat(sessionId: string, memberId: string): OpResult {
    const found: { course: Course; session: Session } | undefined = this.findSession(sessionId);
    if (found === undefined) {
      return { ok: false, message: '课时不存在' };
    }
    const session: Session = found.session;
    if (session.status === 'completed' || session.status === 'cancelled') {
      return { ok: false, message: '该课时已结束' };
    }
    if (session.bookedMemberIds.indexOf(memberId) >= 0) {
      return { ok: false, message: '该会员已预约' };
    }
    if (session.bookedMemberIds.length >= session.capacity) {
      return { ok: false, message: '名额已满' };
    }
    session.bookedMemberIds.push(memberId);
    if (session.bookedMemberIds.length >= session.capacity) {
      session.status = 'full';
    }
    const m: Member | undefined = this.findMember(memberId);
    const name: string = m !== undefined ? m.name : '会员';
    this.logActivity('session-booked', `「${name}」预约「${found.course.title}」`);
    this.persist();
    return { ok: true, message: '预约成功' };
  }

  markAttendance(sessionId: string, memberIds: string[]): OpResult {
    const found: { course: Course; session: Session } | undefined = this.findSession(sessionId);
    if (found === undefined) {
      return { ok: false, message: '课时不存在' };
    }
    const session: Session = found.session;
    session.attendedMemberIds = memberIds;
    session.status = 'completed';
    this.persist();
    return { ok: true, message: '已记录到课' };
  }

  // ===== Inventory =====
  addStockItem(input: {
    name: string; unit: string; quantity: number; lowStockThreshold: number;
  }): OpResult {
    const name: string = input.name.trim();
    if (name.length === 0) {
      return { ok: false, message: '请输入物料名称' };
    }
    const item: StockItem = {
      id: this.nextId('stk'),
      name: name,
      unit: input.unit.trim(),
      quantity: Math.max(0, input.quantity),
      lowStockThreshold: Math.max(0, input.lowStockThreshold),
      history: [],
      createdAt: this.now(),
    };
    this.data.inventory.push(item);
    this.persist();
    return { ok: true, message: '已添加物料' };
  }

  adjustStock(itemId: string, delta: number, reason: string): OpResult {
    const it: StockItem | undefined = this.getStockItem(itemId);
    if (it === undefined) {
      return { ok: false, message: '物料不存在' };
    }
    if (delta === 0) {
      return { ok: false, message: '调整数量不可为 0' };
    }
    const next: number = Math.max(0, it.quantity + delta);
    const realDelta: number = next - it.quantity;
    it.quantity = next;
    it.history.push({
      id: this.nextId('adj'),
      delta: realDelta,
      reason: reason.trim(),
      source: 'manual',
      relatedId: '',
      createdAt: this.now(),
    });
    this.logActivity('stock-adjusted', `「${it.name}」库存调整 ${realDelta > 0 ? '+' : ''}${realDelta}`);
    this.persist();
    return { ok: true, message: '已调整库存' };
  }

  deductForSession(courseId: string, sessionId: string, attendeeCount: number): OpResult {
    const c: Course | undefined = this.getCourse(courseId);
    if (c === undefined) {
      return { ok: false, message: '课程不存在' };
    }
    const session: Session | undefined = c.sessions.find((s: Session) => s.id === sessionId);
    if (session === undefined) {
      return { ok: false, message: '课时不存在' };
    }
    if (session.materialDeducted) {
      return { ok: false, message: '该课时物料已扣减' };
    }
    if (!(attendeeCount > 0)) {
      return { ok: false, message: '参与人数需大于 0' };
    }
    if (c.materials.length === 0) {
      session.materialDeducted = true;
      this.persist();
      return { ok: true, message: '该课程无关联物料' };
    }
    const warnings: string[] = [];
    const now: number = this.now();
    for (const mat of c.materials) {
      const it: StockItem | undefined = this.getStockItem(mat.stockItemId);
      if (it === undefined) {
        continue;
      }
      const need: number = mat.quantityPerAttendee * attendeeCount;
      const before: number = it.quantity;
      const after: number = Math.max(0, before - need);
      const realDelta: number = after - before;
      it.quantity = after;
      it.history.push({
        id: this.nextId('adj'),
        delta: realDelta,
        reason: `「${c.title}」课时消耗 ×${attendeeCount}`,
        source: 'course',
        relatedId: sessionId,
        createdAt: now,
      });
      if (after < need) {
        warnings.push(`「${it.name}」库存不足`);
      }
    }
    session.materialDeducted = true;
    this.logActivity('stock-deducted', `「${c.title}」扣减物料 ×${attendeeCount}`);
    this.persist();
    const msg: string = warnings.length > 0 ? `已扣减（${warnings.join('；')}）` : '已扣减库存';
    return { ok: true, message: msg };
  }

  // ===== Settings =====
  saveSettings(input: {
    studioName: string; checkinPoints: number; consumptionRatio: number; dormantDays: number;
  }): OpResult {
    const checkin: number = Math.max(0, Math.round(input.checkinPoints));
    const ratio: number = Math.max(0, input.consumptionRatio);
    const dormant: number = Math.max(0, Math.round(input.dormantDays));
    if (checkin <= 0 && ratio <= 0) {
      return { ok: false, message: '签到积分与消费比例不可同时为 0' };
    }
    this.data.settings = {
      studioName: input.studioName.trim(),
      checkinPoints: checkin,
      consumptionRatio: ratio,
      dormantDays: dormant,
    };
    this.logActivity('settings-saved', '已保存工作室设置');
    this.persist();
    return { ok: true, message: '设置已保存' };
  }

  // ===== Selectors =====
  queryMembers(query: string, sortMode: MemberSortMode): Member[] {
    const q: string = query.trim().toLowerCase();
    let list: Member[] = this.data.members.filter((m: Member) => {
      if (q.length === 0) {
        return true;
      }
      return m.name.toLowerCase().indexOf(q) >= 0
        || m.phone.toLowerCase().indexOf(q) >= 0
        || m.crafts.some((craft: string) => craft.toLowerCase().indexOf(q) >= 0);
    });
    if (sortMode === 'name') {
      list = list.slice().sort((a: Member, b: Member) => a.name.localeCompare(b.name));
    } else {
      list = list.slice().sort((a: Member, b: Member) => b.lastVisitAt - a.lastVisitAt);
    }
    return list;
  }

  queryCourses(query: string, category: string): Course[] {
    const q: string = query.trim().toLowerCase();
    return this.data.courses.filter((c: Course) => {
      if (category.length > 0 && c.category !== category) {
        return false;
      }
      if (q.length === 0) {
        return true;
      }
      return c.title.toLowerCase().indexOf(q) >= 0 || c.description.toLowerCase().indexOf(q) >= 0;
    });
  }

  queryInventory(query: string, showLowStockOnly: boolean): StockItem[] {
    const q: string = query.trim().toLowerCase();
    return this.data.inventory.filter((it: StockItem) => {
      if (showLowStockOnly && it.quantity > it.lowStockThreshold) {
        return false;
      }
      if (q.length === 0) {
        return true;
      }
      return it.name.toLowerCase().indexOf(q) >= 0;
    });
  }

  lowStockItems(): StockItem[] {
    return this.data.inventory.filter((it: StockItem) => it.quantity <= it.lowStockThreshold);
  }

  hasLowStockAlert(): boolean {
    return this.lowStockItems().length > 0;
  }

  todayClasses(now: number): SessionView[] {
    const key: string = this.dateKey(now);
    return this.collectSessions((s: Session) => this.dateKey(s.startAt) === key);
  }

  recentActivity(limit: number): ActivityLog[] {
    const all: ActivityLog[] = this.data.activityLog.slice();
    all.sort((a: ActivityLog, b: ActivityLog) => b.createdAt - a.createdAt);
    return all.slice(0, limit);
  }

  monthGrid(year: number, month: number): MonthGrid {
    const first: Date = new Date(year, month, 1);
    const startWeekday: number = first.getDay(); // 0=Sun
    const daysInMonth: number = new Date(year, month + 1, 0).getDate();
    const sessionCountByKey: Map<string, number> = this.sessionCountByDateKey();

    const days: CalendarDay[] = [];

    // leading days from previous month
    const prevMonth: number = month === 0 ? 11 : month - 1;
    const prevYear: number = month === 0 ? year - 1 : year;
    const daysInPrev: number = new Date(prevYear, prevMonth + 1, 0).getDate();
    for (let i = startWeekday - 1; i >= 0; i--) {
      const dayNum: number = daysInPrev - i;
      days.push(this.buildCalendarDay(prevYear, prevMonth, dayNum, false, sessionCountByKey));
    }
    // current month days
    for (let d = 1; d <= daysInMonth; d++) {
      days.push(this.buildCalendarDay(year, month, d, true, sessionCountByKey));
    }
    // trailing to complete final week
    while (days.length % 7 !== 0) {
      const last: CalendarDay = days[days.length - 1];
      const next: Date = new Date(last.ms + DAY_MS);
      days.push(this.buildCalendarDay(next.getFullYear(), next.getMonth(), next.getDate(), false, sessionCountByKey));
    }

    return {
      year: year,
      month: month,
      title: `${year}年${month + 1}月`,
      days: days,
    };
  }

  sessionsOnDay(ms: number): SessionView[] {
    const key: string = this.dateKey(ms);
    return this.collectSessions((s: Session) => this.dateKey(s.startAt) === key);
  }

  // ===== private helpers =====
  private findMember(id: string): Member | undefined {
    return this.data.members.find((m: Member) => m.id === id) || undefined;
  }

  private memberIndex(id: string): number {
    return this.data.members.findIndex((m: Member) => m.id === id);
  }

  private findSession(sessionId: string): { course: Course; session: Session } | undefined {
    for (const course of this.data.courses) {
      const s: Session | undefined = course.sessions.find((sess: Session) => sess.id === sessionId);
      if (s !== undefined) {
        return { course: course, session: s };
      }
    }
    return undefined;
  }

  private collectSessions(predicate: (s: Session) => boolean): SessionView[] {
    const out: SessionView[] = [];
    for (const course of this.data.courses) {
      for (const session of course.sessions) {
        if (predicate(session)) {
          out.push({
            sessionId: session.id,
            courseId: course.id,
            courseTitle: course.title,
            startAt: session.startAt,
            bookedCount: session.bookedMemberIds.length,
            capacity: course.capacity,
            status: session.status,
          });
        }
      }
    }
    out.sort((a: SessionView, b: SessionView) => a.startAt - b.startAt);
    return out;
  }

  private sessionCountByDateKey(): Map<string, number> {
    const map: Map<string, number> = new Map<string, number>();
    for (const course of this.data.courses) {
      for (const session of course.sessions) {
        const k: string = this.dateKey(session.startAt);
        const cur: number = map.get(k) || 0;
        map.set(k, cur + 1);
      }
    }
    return map;
  }

  private buildCalendarDay(y: number, m: number, d: number, inMonth: boolean,
    counts: Map<string, number>): CalendarDay {
    const ms: number = new Date(y, m, d, 0, 0, 0, 0).getTime();
    const key: string = this.dateKey(ms);
    return {
      dateKey: key,
      day: d,
      inMonth: inMonth,
      sessionCount: counts.get(key) || 0,
      ms: ms,
    };
  }

  private dateKey(ms: number): string {
    const d: Date = new Date(ms);
    const y: number = d.getFullYear();
    const m: number = d.getMonth() + 1;
    const day: number = d.getDate();
    const mm: string = m < 10 ? `0${m}` : `${m}`;
    const dd: string = day < 10 ? `0${day}` : `${day}`;
    return `${y}-${mm}-${dd}`;
  }
}

