1	// AppStore.ets
2	//
3	// Central in-memory state + all domain operations for 手作·印记.
4	// Headless-logic phase: implements behavior from ui-behavior.json
5	// (member/points/portfolio/dormant/course/booking/inventory/settings
6	// flows). UI event wiring + observable decorators land in visual integration.
7	//
8	// Persistence: every mutating op triggers a debounced Store.save().
9	// Reactivity: state is plain data here; visual integration will bind it
10	// through @Observed/@State. Selectors are pure derivations.
11	
12	import { common } from '@kit.AbilityKit';
13	import {
14	  AppData, Member, Course, Session, StockItem, Settings, ActivityLog,
15	  PortfolioImage, SkillLevel, CourseMaterial,
16	  SessionStatus, ActivityType, emptyAppData,
17	} from '../common/models/Models';
18	import { Store } from './Store';
19	
20	export interface OpResult {
21	  ok: boolean;
22	  message: string;
23	}
24	
25	export interface MemberInput {
26	  name: string;
27	  phone: string;
28	  note: string;
29	  crafts: string[];
30	  skillLevel: SkillLevel;
31	}
32	
33	export interface MemberPatch {
34	  name?: string;
35	  phone?: string;
36	  note?: string;
37	  crafts?: string[];
38	  skillLevel?: SkillLevel;
39	  avatar?: string;
40	}
41	
42	export interface CourseInput {
43	  title: string;
44	  description: string;
45	  cover: string;
46	  durationMin: number;
47	  capacity: number;
48	  category: string;
49	  materials: CourseMaterial[];
50	}
51	
52	export interface StockInput {
53	  name: string;
54	  unit: string;
55	  quantity: number;
56	  lowStockThreshold: number;
57	}
58	
59	export interface SettingsInput {
60	  studioName: string;
61	  checkinPoints: number;
62	  consumptionRatio: number;
63	  dormantDays: number;
64	}
65	
66	export interface SessionRef {
67	  course: Course;
68	  session: Session;
69	}
70	
71	export interface SessionView {
72	  sessionId: string;
73	  courseId: string;
74	  courseTitle: string;
75	  startAt: number;
76	  bookedCount: number;
77	  capacity: number;
78	  status: SessionStatus;
79	}
80	
81	export interface CalendarDay {
82	  dateKey: string; // YYYY-MM-DD
83	  day: number;
84	  inMonth: boolean;
85	  sessionCount: number;
86	  ms: number;
87	}
88	
89	export interface MonthGrid {
90	  year: number;
91	  month: number; // 0-based
92	  title: string;
93	  days: CalendarDay[];
94	}
95	
96	export type MemberSortMode = 'recent' | 'name';
97	
98	const DAY_MS: number = 24 * 60 * 60 * 1000;
99	const MAX_ACTIVITY: number = 200;
100	
101	export class AppStore {
102	  private static instance: AppStore | null = null;
103	
104	  private data: AppData = emptyAppData();
105	  private store: Store = new Store();
106	  private initialized: boolean = false;
107	
108	  static getInstance(): AppStore {
109	    if (AppStore.instance === null) {
110	      AppStore.instance = new AppStore();
111	    }
112	    return AppStore.instance;
113	  }
114	
115	  async init(context: common.Context): Promise<void> {
116	    this.store.attach(context);
117	    this.data = await this.store.load();
118	    this.initialized = true;
119	  }
120	
121	  isInitialized(): boolean {
122	    return this.initialized;
123	  }
124	
125	  // ----- raw accessors (for controllers / visual integration) -----
126	  getMembers(): Member[] {
127	    return this.data.members;
128	  }
129	
130	  getCourses(): Course[] {
131	    return this.data.courses;
132	  }
133	
134	  getInventory(): StockItem[] {
135	    return this.data.inventory;
136	  }
137	
138	  getSettings(): Settings {
139	    return this.data.settings;
140	  }
141	
142	  getMember(id: string): Member | undefined {
143	    return this.findMember(id);
144	  }
145	
146	  getCourse(id: string): Course | undefined {
147	    return this.data.courses.find((c: Course) => c.id === id) || undefined;
148	  }
149	
150	  getStockItem(id: string): StockItem | undefined {
151	    return this.data.inventory.find((it: StockItem) => it.id === id) || undefined;
152	  }
153	
154	  // ----- id helpers -----
155	  private nextId(prefix: string): string {
156	    this.data.idCounter += 1;
157	    return `${prefix}_${this.data.idCounter}`;
158	  }
159	
160	  private now(): number {
161	    return Date.now();
162	  }
163	
164	  private persist(): void {
165	    this.store.save(this.data);
166	  }
167	
168	  // ----- activity log -----
169	  private logActivity(type: ActivityType, summary: string): void {
170	    const entry: ActivityLog = {
171	      id: this.nextId('act'),
172	      type: type,
173	      summary: summary,
174	      createdAt: this.now(),
175	    };
176	    this.data.activityLog.push(entry);
177	    if (this.data.activityLog.length > MAX_ACTIVITY) {
178	      this.data.activityLog.splice(0, this.data.activityLog.length - MAX_ACTIVITY);
179	    }
180	  }
181	
182	  // ===== Member =====
183	  addMember(input: MemberInput): OpResult {
184	    const name: string = input.name.trim();
185	    if (name.length === 0) {
186	      return { ok: false, message: '请输入会员姓名' };
187	    }
188	    const now: number = this.now();
189	    const m: Member = {
190	      id: this.nextId('mem'),
191	      name: name,
192	      avatar: '',
193	      phone: input.phone.trim(),
194	      note: input.note.trim(),
195	      crafts: input.crafts,
196	      skillLevel: input.skillLevel,
197	      points: 0,
198	      createdAt: now,
199	      lastVisitAt: 0,
200	      lifetimeConsumption: 0,
201	      reachedOutAt: 0,
202	      portfolio: [],
203	      pointsHistory: [],
204	    };
205	    this.data.members.push(m);
206	    this.logActivity('member-added', `新增会员「${name}」`);
207	    this.persist();
208	    return { ok: true, message: '已添加会员' };
209	  }
210	
211	  updateMember(id: string, patch: MemberPatch): OpResult {
212	    const idx: number = this.memberIndex(id);
213	    if (idx < 0) {
214	      return { ok: false, message: '会员不存在' };
215	    }
216	    const cur: Member = this.data.members[idx];
217	    const updated: Member = {
218	      id: cur.id,
219	      name: patch.name !== undefined ? patch.name.trim() : cur.name,
220	      avatar: patch.avatar !== undefined ? patch.avatar : cur.avatar,
221	      phone: patch.phone !== undefined ? patch.phone.trim() : cur.phone,
222	      note: patch.note !== undefined ? patch.note.trim() : cur.note,
223	      crafts: patch.crafts !== undefined ? patch.crafts : cur.crafts,
224	      skillLevel: patch.skillLevel !== undefined ? patch.skillLevel : cur.skillLevel,
225	      points: cur.points,
226	      createdAt: cur.createdAt,
227	      lastVisitAt: cur.lastVisitAt,
228	      lifetimeConsumption: cur.lifetimeConsumption,
229	      reachedOutAt: cur.reachedOutAt,
230	      portfolio: cur.portfolio,
231	      pointsHistory: cur.pointsHistory,
232	    };
233	    this.data.members[idx] = updated;
234	    this.persist();
235	    return { ok: true, message: '已更新会员' };
236	  }
237	
238	  deleteMember(id: string): OpResult {
239	    const idx: number = this.memberIndex(id);
240	    if (idx < 0) {
241	      return { ok: false, message: '会员不存在' };
242	    }
243	    this.data.members.splice(idx, 1);
244	    // cleanup bookings/attendance across sessions
245	    for (const course of this.data.courses) {
246	      for (const session of course.sessions) {
247	        session.bookedMemberIds = session.bookedMemberIds.filter((bid: string) => bid !== id);
248	        session.attendedMemberIds = session.attendedMemberIds.filter((aid: string) => aid !== id);
249	        if (session.status === 'full' && session.bookedMemberIds.length < course.capacity) {
250	          session.status = 'open';
251	        }
252	      }
253	    }
254	    this.persist();
255	    return { ok: true, message: '已删除会员' };
256	  }
257	
258	  // ===== Points =====
259	  checkinMember(memberId: string): OpResult {
260	    const m: Member | undefined = this.findMember(memberId);
261	    if (m === undefined) {
262	      return { ok: false, message: '会员不存在' };
263	    }
264	    const award: number = this.data.settings.checkinPoints;
265	    const now: number = this.now();
266	    m.points += award;
267	    m.lastVisitAt = now;
268	    m.pointsHistory.push({
269	      id: this.nextId('pts'),
270	      delta: award,
